/**
 * Code Node: Normalize Article + Synthesize feed_match
 *
 * Input: one item shaped like your API article record:
 *  - _id, tier, category, feedspot_feed_id, feedspot_folder_id, score,
 *    title, content_snippet, published_at_ms, pub_date, article_link
 *
 * Output: keeps original fields, adds:
 *  - link (normalized)
 *  - pub_date_ms (normalized)
 *  - article_host / article_root_domain
 *  - feed_match (object) + feed_match_status/reason/method
 *
 * Goal: Make downstream Pare nodes and Rank prompt work with minimal changes.
 */

function safeString(v) {
  return (v === null || v === undefined) ? "" : String(v);
}

function normalizeHost(host) {
  host = safeString(host).trim().toLowerCase();
  host = host.replace(/^\.+|\.+$/g, "");
  host = host.replace(/^www\./, "");
  host = host.replace(/^amp\./, "");
  host = host.replace(/^rss\./, "");
  host = host.replace(/^feeds\./, "");
  return host;
}

function getRootDomain(host) {
  host = normalizeHost(host);
  if (!host) return "";
  const parts = host.split(".").filter(Boolean);
  if (parts.length <= 2) return host;
  return parts.slice(-2).join(".");
}

function extractHostFromUrl(url) {
  url = safeString(url).trim();
  if (!url) return "";
  if (url.startsWith("//")) url = "https:" + url;
  if (!/^https?:\/\//i.test(url)) return "";
  const m = url.match(/^https?:\/\/([^\/?#]+)(?:[\/?#]|$)/i);
  return m ? normalizeHost(m[1]) : "";
}

function toMsFromDateString(s) {
  const str = safeString(s);
  if (!str) return 0;
  const d = new Date(str);
  const ms = d.getTime();
  return Number.isFinite(ms) ? ms : 0;
}

// Process THIS item only
const j = $json;

// Normalize link + pub_date_ms
const link = safeString(j.article_link || j.link || j.canonical_id || "");
const pub_date_ms =
  (typeof j.published_at_ms === "number" && Number.isFinite(j.published_at_ms) && j.published_at_ms > 0)
    ? j.published_at_ms
    : (typeof j.pub_date_ms === "number" && Number.isFinite(j.pub_date_ms) && j.pub_date_ms > 0)
      ? j.pub_date_ms
      : toMsFromDateString(j.pub_date);

// Compute host/root domain for analytics + fallback grouping
const articleHost = extractHostFromUrl(link);
const articleRoot = getRootDomain(articleHost);

// Build feed_match from the article’s own metadata
// Keep properties aligned with the schema your Rank node expects.
const feed_match = {
  _id: safeString(j._id) || null,
  name: null, // not provided by API payload; keep null
  tier: safeString(j.tier) || null,
  category: safeString(j.category) || null,
  rss_url: null, // no longer applicable in this articles-only pipeline
  dinner_score: null, // not provided; keep null
  feedspot_feed_id: safeString(j.feedspot_feed_id) || null,
  feedspot_folder_id: safeString(j.feedspot_folder_id) || null,
};

// Determine match status (now “matched” means “has feed identifiers”)
const hasFeedId = !!feed_match.feedspot_feed_id || !!feed_match._id;

return {
  ...j,

  // normalized fields expected downstream
  link: link || null,
  canonical_id: link || null, // optional convenience; harmless
  pub_date_ms: pub_date_ms || 0,

  // host/domain enrichment
  article_host: articleHost || null,
  article_root_domain: articleRoot || null,

  // match metadata for downstream logic
  feed_match_status: hasFeedId ? "matched" : "unmatched",
  feed_match_reason: hasFeedId ? "article already includes feed identifiers" : "missing_feed_identifiers",
  match_method: hasFeedId ? "embedded" : null,

  // synthesized feed object
  feed_match,
};

/**
 * Normalize Rankings (Code node)
 *
 * Input: raw "Rank via LLM" item (Responses API style payload),
 *        i.e. $json.output[0].content[0].text = { rankings: [...], selected_canonical_ids: [...] }
 *
 * Output:
 *  - rankings: normalized array
 *  - selected_canonical_ids: resolved array (never empty unless rankings empty)
 *  - selected_article_ids: resolved array (aligned with selected_canonical_ids when possible)
 *  - email_subject: string
 *  - email_body_text: string (plain text, email-safe)
 *  - webhook_payload: object (JSON-safe)
 */

function pickRankingsPayload(root) {
  // Preferred: Responses API shape
  const t = root?.output?.[0]?.content?.[0]?.text;

  // If model returned parsed object already
  if (t && typeof t === "object") return t;

  // If model returned JSON string
  if (typeof t === "string" && t.trim()) {
    try {
      const parsed = JSON.parse(t);
      if (parsed && typeof parsed === "object") return parsed;
    } catch (e) {
      // fall through
    }
  }

  // Fallback: some nodes store model output directly
  if (root?.rankings && Array.isArray(root.rankings)) return root;

  return null;
}

function safeStr(v) {
  return String(v ?? "").trim();
}

function truncate(s, max = 280) {
  s = safeStr(s);
  if (!s) return "";
  if (s.length <= max) return s;
  return s.slice(0, max - 1).trimEnd() + "…";
}

function coerceMs(v) {
  if (typeof v === "number" && Number.isFinite(v)) return v;
  // Sometimes ms sneaks in as a numeric string
  if (typeof v === "string" && v.trim() && !Number.isNaN(Number(v))) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  }
  return null;
}

function getPubMs(article) {
  // Prefer your normalized field
  let ms = coerceMs(article?.pub_date_ms);
  if (ms) return ms;

  // Fallbacks (depending on upstream nodes)
  ms = coerceMs(article?.published_at_ms);
  if (ms) return ms;

  return null;
}

function fmtDate(ms) {
  ms = coerceMs(ms);
  if (!ms || ms <= 0) return "";
  const d = new Date(ms);
  if (Number.isNaN(d.getTime())) return "";
  return d.toLocaleDateString("en-US", {
    timeZone: "America/Chicago",
    year: "numeric",
    month: "short",
    day: "2-digit",
  });
}

const payload = pickRankingsPayload($json);
if (!payload) {
  throw new Error("Normalize Rankings: cannot find rankings payload on input item");
}

const rawRankings = Array.isArray(payload.rankings) ? payload.rankings : [];
const rawSelected = Array.isArray(payload.selected_canonical_ids) ? payload.selected_canonical_ids : [];

// Normalize rankings into a consistent, compact shape
const rankings = rawRankings
  .map((r) => {
    const a = r?.article || {};

    const canonical = safeStr(r?.canonical_id || a?.canonical_id || a?.link);
    const articleCanonical = safeStr(a?.canonical_id || a?.link);

    // Prefer ranking-level article_id if present, else article.article_id
    const articleId = safeStr(r?.article_id || a?.article_id) || null;

    return {
      rank: Number(r?.rank ?? 0),
      canonical_id: canonical,
      article_id: articleId,
      score: Number(r?.score ?? 0),
      reason: safeStr(r?.reason),
      article: {
        canonical_id: articleCanonical,
        article_id: articleId,
        title: safeStr(a?.title),
        snippet: safeStr(a?.snippet),
        category: a?.category ?? null,
        source_name: a?.source_name ?? null,

        // keep your field name, but fill it if you can
        pub_date_ms: coerceMs(a?.pub_date_ms) ?? coerceMs(a?.published_at_ms) ?? null,

        link: safeStr(a?.link || a?.canonical_id),
        creator: a?.creator ?? null,
        article_host: a?.article_host ?? null,
        article_root_domain: a?.article_root_domain ?? null,
        feed_match_status: a?.feed_match_status ?? null,
        feed_match_reason: a?.feed_match_reason ?? null,
        match_method: a?.match_method ?? null,
        feed_match: a?.feed_match ?? null,
      },
    };
  })
  .filter((r) => r.rank > 0 && r.canonical_id);

// Sort defensively
rankings.sort((x, y) => x.rank - y.rank);

// Resolve selected list (never empty if rankings exist)
const resolvedSelected =
  rawSelected.length > 0
    ? rawSelected.map((x) => safeStr(x)).filter(Boolean)
    : rankings.slice(0, 10).map((r) => r.canonical_id);

const canonicalToArticleId = new Map();
for (const r of rankings) {
  const aid = safeStr(r?.article_id || r?.article?.article_id);
  if (r.canonical_id && aid) canonicalToArticleId.set(r.canonical_id, aid);
}

const resolvedSelectedArticleIds = resolvedSelected
  .map((cid) => canonicalToArticleId.get(cid) || null)
  .filter(Boolean);

// Build email subject + plain-text body
const tz = "America/Chicago";
const today = new Date().toLocaleDateString("en-US", {
  timeZone: tz,
  weekday: "short",
  year: "numeric",
  month: "short",
  day: "2-digit",
});

const email_subject = `Daily Digest — ${today}`;

const lines = [];
lines.push(`Daily Digest (${today})`);
lines.push("");
lines.push("Top items:");
lines.push("");

for (const r of rankings) {
  const a = r.article;
  const title = a.title || r.canonical_id;
  const source = safeStr(a.source_name);
  const cat = safeStr(a.category);
  const date = fmtDate(getPubMs(a));
  const meta = [source, cat, date].filter(Boolean).join(" | ");

  lines.push(`${r.rank}) ${title}`);
  if (meta) lines.push(`   ${meta}`);
  if (r.article_id) lines.push(`   Article ID: ${r.article_id}`);
  if (r.reason) lines.push(`   Why: ${r.reason}`);
  if (a.snippet) lines.push(`   ${truncate(a.snippet, 300)}`);
  if (a.link) lines.push(`   Link: ${a.link}`);
  lines.push("");
}

const email_body_text = lines.join("\n");

// Build webhook payload (structured)
const webhook_payload = {
  generated_at_iso: new Date().toISOString(),
  subject: email_subject,
  selected_canonical_ids: resolvedSelected,
  selected_article_ids: resolvedSelectedArticleIds,
  rankings,
};

return {
  rankings,
  selected_canonical_ids: resolvedSelected,
  selected_article_ids: resolvedSelectedArticleIds,
  email_subject,
  email_body_text,
  webhook_payload,
};

/**
 * Pare 02 — Drop Low-Value Patterns (minimal, title+link centric)
 * Key rule: no link => drop
 */

const ENABLE_TITLE_FILTER = true;
const ENABLE_LINK_FILTER = true;
const CASE_INSENSITIVE = true;

const TITLE_DROP_PATTERNS = [
  "\\btrivia\\b",
  "\\bslideshow\\b",
  "\\bpodcast\\b",
  "\\btop\\s+\\d+\\b",
  "\\btop\\s+(stories|podcasts|roads|bridges|video interviews|cover stories)\\b",
  "\\bawards\\b",
  "\\broundup\\b",
];

const LINK_DROP_PATTERNS = [
  "\\bmedia-gallery\\b",
  "\\bpodcast\\b",
  "\\bslideshow\\b",
  "\\bawards\\b",
];

function makeRegexes(patterns) {
  const flags = CASE_INSENSITIVE ? "i" : "";
  return patterns.map((p) => new RegExp(p, flags));
}

const titleRegexes = makeRegexes(TITLE_DROP_PATTERNS);
const linkRegexes = makeRegexes(LINK_DROP_PATTERNS);

function matchesAny(str, regexes) {
  if (!str) return false;
  for (const r of regexes) if (r.test(str)) return true;
  return false;
}

const kept = [];

for (const item of items) {
  const a = item.json || {};
  const title = String(a.title || "");
  const link = String(a.link || a.article_link || a.canonical_id || "").trim();

  // Hard requirement: no link => no article
  if (!link) continue;

  const dropByTitle = ENABLE_TITLE_FILTER && matchesAny(title, titleRegexes);
  const dropByLink = ENABLE_LINK_FILTER && matchesAny(link, linkRegexes);

  if (dropByTitle || dropByLink) continue;

  kept.push(item);
}

return kept;

/**
 * n8n Code Node: Pare 03 — Cap Per Feed (v2)
 *
 * Groups by feed identifier and keeps the newest N per feed.
 *
 * Feed key priority (intended for your current contract):
 *  1) feedspot_feed_id (top-level or inside feed_match)
 *  2) feed_match.feedspot_feed_id
 *  3) feed_match._id (NOT ideal; but available)
 *  4) top-level feedspot_feed_id (again, as fallback)
 *
 * Date priority:
 *  1) published_at_ms
 *  2) pub_date_ms
 *  3) parse pub_date
 */

const MAX_PER_FEED = 8;          // <-- modify
const REQUIRE_FEED_MATCH = true; // <-- modify
const SORT_DESC = true;          // <-- modify (newest-first)

function safeString(v) {
  return (v === null || v === undefined) ? "" : String(v);
}

function toMsFromDateString(s) {
  const str = safeString(s).trim();
  if (!str) return -Infinity;
  const d = new Date(str);
  const ms = d.getTime();
  return Number.isFinite(ms) ? ms : -Infinity;
}

function getMs(article) {
  const p1 = article.published_at_ms;
  if (typeof p1 === "number" && Number.isFinite(p1) && p1 > 0) return p1;

  const p2 = article.pub_date_ms;
  if (typeof p2 === "number" && Number.isFinite(p2) && p2 > 0) return p2;

  return toMsFromDateString(article.pub_date);
}

function getFeedId(article) {
  // Prefer top-level feedspot_feed_id first (your current payload has it)
  const top = safeString(article.feedspot_feed_id).trim();
  if (top) return top;

  const fm = article.feed_match && typeof article.feed_match === "object" ? article.feed_match : null;
  if (fm) {
    const fmFeed = safeString(fm.feedspot_feed_id).trim();
    if (fmFeed) return fmFeed;

    const fmId = safeString(fm._id).trim();
    if (fmId) return fmId;
  }

  return null;
}

function getStableItemKey(article) {
  // Only used when REQUIRE_FEED_MATCH=false, to avoid collapsing all unmatched items into one group
  return (
    safeString(article.canonical_id).trim() ||
    safeString(article.link).trim() ||
    safeString(article.article_link).trim() ||
    safeString(article._id).trim() ||
    "unknown"
  );
}

// Group items by feedId
const groups = new Map();

for (const item of items) {
  const a = item.json || {};
  const feedId = getFeedId(a);

  if (!feedId) {
    if (!REQUIRE_FEED_MATCH) {
      const fallbackId = `__no_feed__:${getStableItemKey(a)}`;
      if (!groups.has(fallbackId)) groups.set(fallbackId, []);
      groups.get(fallbackId).push(item);
    }
    continue;
  }

  if (!groups.has(feedId)) groups.set(feedId, []);
  groups.get(feedId).push(item);
}

const kept = [];

for (const [, arr] of groups.entries()) {
  arr.sort((x, y) => {
    const ax = getMs(x.json || {});
    const ay = getMs(y.json || {});
    return SORT_DESC ? ay - ax : ax - ay;
  });

  kept.push(...arr.slice(0, Math.max(0, MAX_PER_FEED)));
}

// Optional: preserve global ordering (newest-first)
kept.sort((x, y) => {
  const ax = getMs(x.json || {});
  const ay = getMs(y.json || {});
  return SORT_DESC ? ay - ax : ax - ay;
});

return kept;

/**
 * n8n Code Node: Pare 04 — Cap Per Category (v2)
 *
 * Groups by category and keeps newest N per category.
 * Enforces "no one category dominates the digest."
 *
 * Category priority:
 *  1) top-level category
 *  2) feed_match.category (fallback)
 *
 * Date priority:
 *  1) published_at_ms
 *  2) pub_date_ms
 *  3) parse pub_date
 */

const MAX_PER_CATEGORY = 8;        // <-- modify
const DEFAULT_CATEGORY = "uncategorized"; // <-- modify
const REQUIRE_CATEGORY = false;     // <-- modify (true = drop items where category missing/empty)
const SORT_DESC = true;             // <-- modify (newest-first)

function safeString(v) {
  return (v === null || v === undefined) ? "" : String(v);
}

function toMsFromDateString(s) {
  const str = safeString(s).trim();
  if (!str) return -Infinity;
  const d = new Date(str);
  const ms = d.getTime();
  return Number.isFinite(ms) ? ms : -Infinity;
}

function getMs(article) {
  const p1 = article.published_at_ms;
  if (typeof p1 === "number" && Number.isFinite(p1) && p1 > 0) return p1;

  const p2 = article.pub_date_ms;
  if (typeof p2 === "number" && Number.isFinite(p2) && p2 > 0) return p2;

  return toMsFromDateString(article.pub_date);
}

function getCategory(article) {
  // Prefer top-level category (your current payload includes it)
  const top = safeString(article.category).trim();
  if (top) return top;

  // Fallback: feed_match.category
  const fm = article.feed_match && typeof article.feed_match === "object" ? article.feed_match : null;
  const fmCat = fm ? safeString(fm.category).trim() : "";
  if (fmCat) return fmCat;

  return null;
}

const groups = new Map();

for (const item of items) {
  const a = item.json || {};
  let cat = getCategory(a);

  if (!cat) {
    if (REQUIRE_CATEGORY) continue;
    cat = DEFAULT_CATEGORY;
  }

  if (!groups.has(cat)) groups.set(cat, []);
  groups.get(cat).push(item);
}

const kept = [];

for (const [, arr] of groups.entries()) {
  arr.sort((x, y) => {
    const ax = getMs(x.json || {});
    const ay = getMs(y.json || {});
    return SORT_DESC ? ay - ax : ax - ay;
  });

  kept.push(...arr.slice(0, Math.max(0, MAX_PER_CATEGORY)));
}

// Optional: global newest-first ordering
kept.sort((x, y) => {
  const ax = getMs(x.json || {});
  const ay = getMs(y.json || {});
  return SORT_DESC ? ay - ax : ax - ay;
});

return kept;

/**
 * n8n Code Node: Pare 05 — Global Cap (v2)
 *
 * Final overall cap. Sorts newest-first and keeps top N.
 *
 * Date priority:
 *  1) published_at_ms
 *  2) pub_date_ms
 *  3) parse pub_date
 */

const MAX_TOTAL = 50; // <-- modify (you said 30 max)
const SORT_DESC = true; // <-- modify

function safeString(v) {
  return (v === null || v === undefined) ? "" : String(v);
}

function toMsFromDateString(s) {
  const str = safeString(s).trim();
  if (!str) return -Infinity;
  const d = new Date(str);
  const ms = d.getTime();
  return Number.isFinite(ms) ? ms : -Infinity;
}

function getMs(article) {
  const p1 = article.published_at_ms;
  if (typeof p1 === "number" && Number.isFinite(p1) && p1 > 0) return p1;

  const p2 = article.pub_date_ms;
  if (typeof p2 === "number" && Number.isFinite(p2) && p2 > 0) return p2;

  return toMsFromDateString(article.pub_date);
}

const arr = [...items];

arr.sort((x, y) => {
  const ax = getMs(x.json || {});
  const ay = getMs(y.json || {});
  return SORT_DESC ? ay - ax : ax - ay;
});

return arr.slice(0, Math.max(0, MAX_TOTAL));

