={{
  (() => {
    const r = $json.rankings || [];
    const subject = $json.email_subject || 'Daily Digest';
    const MAX_SNIPPET = 320; // tune this

    const lines = [];
    lines.push(subject);
    lines.push('');
    lines.push('Top items:');
    lines.push('These are the randomly picked stories of the last few weeks.');
    lines.push('To review more, go to:');
    lines.push('https://social.tonkaintl.com/tonka-dispatch/rankings');
    lines.push('Sign In');
    lines.push('Under menu Tonka Dispatch, click on Daily Rankings');
    lines.push('');

    const fmtDate = (ms) => {
      if (typeof ms !== 'number' || !isFinite(ms) || ms <= 0) return '';
      const d = new Date(ms);
      if (isNaN(d.getTime())) return '';
      return d.toLocaleDateString('en-US', {
        timeZone: 'America/Chicago',
        year: 'numeric',
        month: 'short',
        day: '2-digit'
      });
    };

    const clean = (s) => String(s || '').replace(/\s+/g, ' ').trim();

    const trunc = (s, max) => {
      s = clean(s);
      if (!s) return '';
      if (s.length <= max) return s;
      return s.slice(0, max - 1).trimEnd() + '…';
    };

    for (const item of r) {
      const a = item.article || {};
      const rank = item.rank ?? '';
      const title = clean(a.title || item.canonical_id || '');
      const link = clean(a.link || item.canonical_id || '');
      const cat = clean(a.category || '');
      const date = fmtDate(a.pub_date_ms);

      // Prefer snippet; if empty, fall back to reason (optional)
      const snippet = trunc(a.snippet, MAX_SNIPPET);
      const reason = trunc(item.reason, MAX_SNIPPET);
      const blurb = snippet || reason;

      const meta = [cat, date].filter(Boolean).join(' | ');

      lines.push(`${rank}) ${title}`);
      if (meta) lines.push(`   ${meta}`);
      if (blurb) lines.push(`   ${blurb}`);
      if (link) lines.push(`   Link: ${link}`);
      lines.push('');
    }

    return lines.join('\n');
  })()
}}
